import { existsSync, mkdirSync, readFileSync, writeFileSync, cpSync } from 'node:fs';
import { dirname, join, resolve } from 'node:path';

const root = process.cwd();
const backupRoot = join(root, 'patch_backups', 'refactor_003_hotfix');
const payload: Record<string,string> = {
  "server/src/rooms/Drop8Room.ts": "",
  "server/tests/room.test.ts": ""
};
const notes = Buffer.from('', 'base64').toString('utf8');

for (const relative of Object.keys(payload)) {
  const target = resolve(root, relative);
  if (!existsSync(target)) {
    console.error(`필수 파일을 찾을 수 없습니다: ${relative}`);
    process.exit(1);
  }
}

mkdirSync(backupRoot, { recursive: true });
for (const relative of Object.keys(payload)) {
  const source = resolve(root, relative);
  const backup = resolve(backupRoot, relative);
  mkdirSync(dirname(backup), { recursive: true });
  cpSync(source, backup, { force: true });
}

const patchNotes = resolve(root, 'docs/PATCH_NOTES.md');
if (existsSync(patchNotes)) {
  const backup = resolve(backupRoot, 'docs/PATCH_NOTES.md');
  mkdirSync(dirname(backup), { recursive: true });
  cpSync(patchNotes, backup, { force: true });
}

for (const [relative, content] of Object.entries(payload)) {
  const target = resolve(root, relative);
  mkdirSync(dirname(target), { recursive: true });
  writeFileSync(target, Buffer.from(content, 'base64'));
}

if (existsSync(patchNotes)) {
  const current = readFileSync(patchNotes, 'utf8');
  if (!current.includes('refactor_003 hotfix')) writeFileSync(patchNotes, current.trimEnd() + '\n' + notes);
}

console.log('DROP 8 refactor_003 hotfix 적용 완료');
console.log(`백업 위치: ${backupRoot}`);
console.log('다음 명령: pnpm typecheck && pnpm lint && pnpm test && pnpm dev:lan');
